import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import '../styles/Auth.css';

const SignUpPage = () => {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const { signup } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();

    if (password !== confirmPassword) {
      return setError('Passwords do not match');
    }

    try {
      setError('');
      setLoading(true);

      const result = await signup(name, email, password);

      if (result.success) {
        navigate('/dashboard');
      } else {
        setError(result.message || 'Failed to create an account');
      }
    } catch (err) {
      setError('Failed to create an account. Please try again.');
    }

    setLoading(false);
  };

  const handleDemoLogin = async () => {
    try {
      setError('');
      setLoading(true);

      // Use demo credentials
      const result = await signup('Demo User', 'demo@example.com', 'password123');

      if (result.success) {
        navigate('/dashboard');
      } else {
        // If demo user already exists, try logging in
        const loginResult = await signup('Demo User', 'demo@example.com', 'password123');
        if (loginResult.success) {
          navigate('/dashboard');
        } else {
          setError('Failed to sign in with demo account');
        }
      }
    } catch (err) {
      setError('Failed to sign in with demo account');
    }

    setLoading(false);
  };

  return (
    <div className="auth-page-container">
      <div className="auth-card">
        <h1 className="auth-title">TaskTrail</h1>
        <h2 className="auth-subtitle">Create Account</h2>
        {error && <div className="error-message">{error}</div>}
        <form onSubmit={handleSubmit} className="auth-form">
          <div className="form-group">
            <label htmlFor="name">Full Name</label>
            <input
              type="text"
              id="name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="email">Email Address</label>
            <input
              type="email"
              id="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              type="password"
              id="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              minLength="6"
            />
            <div className="password-hint">Password must be at least 6 characters long</div>
          </div>
          <div className="form-group">
            <label htmlFor="confirmPassword">Confirm Password</label>
            <input
              type="password"
              id="confirmPassword"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              required
            />
          </div>
          <button type="submit" className="auth-btn primary" disabled={loading}>
            {loading ? 'Creating Account...' : 'Sign Up'}
          </button>
          <div className="divider">
            <span>or</span>
          </div>
          <button 
            type="button" 
            className="auth-btn demo"
            onClick={handleDemoLogin}
            disabled={loading}
          >
            {loading ? 'Signing in...' : 'Try Demo Account'}
          </button>
        </form>
        <div className="auth-links">
          <p>Already have an account? <Link to="/signin">Sign in</Link></p>
        </div>
      </div>
    </div>
  );
};

export default SignUpPage;
